// Step Functions skeleton (patch workflow)
{
  "Comment": "Cross-account SAP patch management workflow",
  "StartAt": "PreFlightChecks",
  "States": {
    "PreFlightChecks": {
      "Type": "Task",
      "Resource": "arn:aws:lambda:region:account:function:preFlightChecks",
      "Next": "ApprovalGate"
    },
    "ApprovalGate": {
      "Type": "WaitForApproval",
      "Next": "PauseSAPServices"
    },
    "PauseSAPServices": {
      "Type": "Task",
      "Resource": "arn:aws:lambda:region:account:function:pauseSAP",
      "Next": "OSPatch"
    },
    "OSPatch": {
      "Type": "Task",
      "Resource": "aws:ssm:executePatchBaseline",
      "Next": "SAPKernelPatch"
    },
    "SAPKernelPatch": {
      "Type": "Task",
      "Resource": "arn:aws:lambda:region:account:function:runSUM",
      "Next": "SAPAppPatch"
    },
    "SAPAppPatch": {
      "Type": "Task",
      "Resource": "arn:aws:lambda:region:account:function:runSUMApp",
      "Next": "ValidateHealth"
    },
    "ValidateHealth": {
      "Type": "Task",
      "Resource": "arn:aws:lambda:region:account:function:healthCheck",
      "Next": "DecisionChoice"
    },
    "DecisionChoice": {
      "Type": "Choice",
      "Choices": [{
        "Variable": "$.healthStatus",
        "StringEquals": "healthy",
        "Next": "ResumeServices"
      }],
      "Default": "Rollback"
    },
    "ResumeServices": {
      "Type": "Task",
      "Resource": "arn:aws:lambda:region:account:function:resumeSAP",
      "Next": "AuditLog"
    },
    "Rollback": {
      "Type": "Task",
      "Resource": "arn:aws:lambda:region:account:function:rollback",
      "Next": "AuditLog"
    },
    "AuditLog": {
      "Type": "Task",
      "Resource": "arn:aws:lambda:region:account:function:auditLog",
      "End": true
    }
  }
}
```

