// Minimal CDK snippet to create the cross-account trust role
import { Stack, StackProps } from 'aws-cdk-lib';
import { Role, ServicePrincipal, Policy, PolicyStatement, Effect, AccountPrincipal } from 'aws-cdk-lib/aws-iam';
