import { Duration } from 'aws-cdk-lib';

export class CrossAccountSapRoleStack extends Stack {
  constructor(scope: Construct, id: string, props?: StackProps) {
    super(scope, id, props);

    const sapAdminRole = new Role(this, 'SapAdminRole', {
      roleName: 'SAP-ParameterAdmin-CrossAccount',
      assumedBy: new ServicePrincipal('sts.amazonaws.com'),
      maxSessionDuration: Duration.hours(12),
    });

    // Trust policy allowing specific Audit account to assume this role
    sapAdminRole.assumeRolePolicy.addStatements(
      new PolicyStatement({
        effect: Effect.ALLOW,
        principals: [new AccountPrincipal('111122223333')], // Audit Account ID
        actions: ['sts:AssumeRole'],
      })
    );

    // Permission policy for SSM Parameter Store access
    const ssmPolicy = new Policy(this, 'SapParameterPolicy', {
      policyName: 'SAP-Parameter-Access-Policy',
      statements: [
        new PolicyStatement({
          effect: Effect.ALLOW,
          actions: [
            'ssm:GetParameter',
            'ssm:PutParameter',
            'ssm:DescribeParameters',
          ],
          resources: ['arn:aws:ssm:*:*:parameter/sap/config/*'],
        }),
      ],
    });

    sapAdminRole.attachInlinePolicy(ssmPolicy);
  }
}
