## CloudWatch Alert Path for Session Revocation

```javascript
// Lambda function to revoke access after 12-hour expiry
import { CloudWatchEventsClient, PutEventsCommand } from '@aws-sdk/client-cloudwatch-events';

const REGION = 'us-east-1';

export const handler = async (event) => {
  try {
    const detail = event.detail || {};
    const roleSessionName = detail.roleSessionName || 'SAP-Admin-Session';

    console.log(`Revoking session: ${roleSessionName}`);

    const cwClient = new CloudWatchEventsClient({ region: REGION });
    await cwClient.send(new PutEventsCommand({
      Entries: [{
        Source: 'sap.access.revocation',
        DetailType: 'Session Revoked',
        Detail: JSON.stringify({ status: 'success', timestamp: new Date().toISOString() }),
      }],
    }));

    return { statusCode: 200, body: 'Session revoked successfully' };
  } catch (error) {
    console.error('Revocation failed:', error);

    const alarmClient = new CloudWatchEventsClient({ region: REGION });
    await alarmClient.send(new PutEventsCommand({
      Entries: [{
        Source: 'sap.access.revocation.failure',
        DetailType: 'Revocation Alarm',
        Detail: JSON.stringify({ error: error.message, timestamp: new Date().toISOString() }),
      }],
    }));

    return { statusCode: 500, body: 'Revocation failed' };
  }
};
```

